INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 21, 0, "vo_asb", "", 72020, 0, "vo_asb_0723", 72, "", "");
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 11, 1, 1, 0, 72021, 10, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 72, 1, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 91, 0, 0, "", 72022, 0, "", 72, "", "");
