INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 11, 1, 1, 0, 142024, 10, "……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 142, 1, 0);
